const output = $input.first().json.stdout;
if (output === 'NO_FILES') {
  throw new Error('No onboarding files found in /recordings/onboarding/');
}
const files = output.trim().split('\n').filter(f => f.length > 0);
return files.map(f => ({ json: { file_path: f, filename: f.split('/').pop() } }));

// Derive company name from filename for account matching
const filename = $json.filename;
const stem = filename.replace(/\.[^.]+$/, '').replace(/_onboarding/i, '').replace(/-/g, ' ').replace(/_/g, ' ');
const company = stem.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
return [{ json: { ...$json, company_name: company } }];

const output = $input.first().json.stdout;
const lines = output.split('\n');
const accountLine = lines.find(l => l.includes('Account ID:'));
const companyLine = lines.find(l => l.includes('Company:'));
const changesLine = lines.find(l => l.includes('Changes:'));

return [{
  json: {
    status: 'success',
    account_id: accountLine ? accountLine.split(':').slice(1).join(':').trim() : 'unknown',
    company: companyLine ? companyLine.split(':').slice(1).join(':').trim() : 'unknown',
    changes: changesLine ? changesLine.split(':').slice(1).join(':').trim() : '0',
    raw_output: output
  }
}];

const items = $input.all();
const success = items.filter(i => i.json.status === 'success').length;
const total = items.length;
const totalChanges = items.reduce((sum, i) => sum + parseInt(i.json.changes || 0), 0);

return [{
  json: {
    summary: `Pipeline B Complete: ${success}/${total} onboarding calls processed, ${totalChanges} total changes`,
    results: items.map(i => i.json)
  }
}];
